  1→import './signup.css'
  2→import React, { useEffect, useState } from "react";
  3→import { useNavigate } from "react-router-dom";
  4→import supabase from '../../utils/supabaseClient';
  5→import Turnstile from 'react-turnstile'
  6→import { useAuth } from '../../Context/useAuth';
  7→import BASE_URL from '../../utils/apiBaseUrl';
  8→import apiRequest from '../../utils/apiRequest';
  9→
 10→const SITE_KEY = import.meta.env.VITE_SITE_KEY;
 11→
 12→const SignUp = () => {
 13→    const { session } = useAuth();
 14→
 15→    const [password, setPassword] = useState('');
 16→    const [email, setEmail] = useState('');
 17→    const [showPass, setShowPass] = useState(false)
 18→    const [errorMessage, setErrorMessage] = useState(null);
 19→    const [isLoadingSignUp, setIsLoadingSignUp] = useState(false)
 20→    const [successMessage, setSuccessMessage] = useState('');
 21→    const navigate = useNavigate();
 22→
 23→    const [captchaToken, setCaptchaToken] = useState(null);
 24→
 25→    const handleShowPass = (e) =>{
 26→        e.preventDefault();
 27→        setShowPass((prev) => !prev)
 28→    }
 29→
 30→    const handleSignUp = async(e) =>{
 31→        e.preventDefault();
 32→        setErrorMessage(null);
 33→        setSuccessMessage('');
 34→        setIsLoadingSignUp(true)
 35→        const validateEmail = (email) =>{
 36→            const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
 37→            return emailRegex.test(email)
 38→        }
 39→        if(!validateEmail(email)){
 40→            setIsLoadingSignUp(false)
 41→           return setErrorMessage('Email is not valid')
 42→        }
 43→        if (!captchaToken) {
 44→            setIsLoadingSignUp(false)
 45→            return setErrorMessage("Please complete the CAPTCHA first.");
 46→        }
 47→
 48→        try {
 49→            const res = await apiRequest(`${BASE_URL}/verify-turnstile`, {
 50→                method: 'POST',
 51→                headers: { 'Content-Type': 'application/json' },
 52→                body: JSON.stringify({ token: captchaToken }),
 53→            })
 54→
 55→            const result = await res.json();
 56→
 57→            if (!result.success) {
 58→                return setErrorMessage("CAPTCHA verification failed. Try again.");
 59→            }
 60→
 61→            const { error: error } = await supabase.auth.signUp({
 62→                email: email,
 63→                password: password
 64→            })
 65→            if(error.message){
 66→                return setErrorMessage(error.message)
 67→            }
 68→            setSuccessMessage('Account created. Check your email to confirm.');
 69→            setTimeout(() => navigate('/home'), 600);
 70→        } catch (error) {
 71→            console.error('Error during sign-up:', error.message);
 72→            setErrorMessage(error.message);
 73→        } finally {
 74→            setEmail('');
 75→            setPassword('');
 76→            setIsLoadingSignUp(false)
 77→        }
 78→
 79→    }
 80→    const handleNavigate = (e) => {
 81→        e.preventDefault();
 82→        return navigate('/login');
 83→    }
 84→
 85→    useEffect(() =>{
 86→        if(session){
 87→            return navigate('/home')
 88→        }
 89→    }, [session, navigate])
 90→
 91→    const isSubmitDisabled = !email || !password || !captchaToken || isLoadingSignUp;
 92→
 93→    return(
 94→        <div className='auth-shell signup-shell'>
 95→            <section className='auth-panel'>
 96→                <div className='brand'>Iskrib</div>
