 1→import supabase from "./supabase.js"
 2→
 3→export const getUserByUsernameService = async(username) => {
 4→    if(!username || typeof username !== 'string'){
 5→        throw {status: 400, message: 'username is required'};
 6→    }
 7→
 8→    const normalizedUsername = username.trim().toLowerCase();
 9→
10→    const { data: users, error: userError } = await supabase
11→        .from('users')
12→        .select('*')
13→        .ilike('username', normalizedUsername)
14→        .limit(1);
15→
16→    if(userError){
17→        console.error('supabase error fetching user by username:', userError.message);
18→        throw {status: 500, message: 'supabase error fetching user by username'};
19→    }
20→
21→    if(!users || users.length === 0){
22→        throw {status: 404, message: 'user not found'};
23→    }
24→
25→    const user = users[0];
26→
27→    const followerCountPromise = supabase
28→        .from('follows')
29→        .select('*', {count: 'exact', head: true})
30→        .eq('following_id', user.id);
31→
32→    const followingCountPromise = supabase
33→        .from('follows')
34→        .select('*', {count: 'exact', head: true})
35→        .eq('follower_id', user.id);
36→
37→    const [followerCountResult, followingCountResult] = await Promise.all([
38→        followerCountPromise, followingCountPromise
39→    ]);
40→
41→    const {count: followerCount, error: errorFollowerCount} = followerCountResult;
42→    const {count: followingCount, error: errorFollowingCount} = followingCountResult;
43→
44→    if(errorFollowerCount || errorFollowingCount){
45→        console.error('supabase error fetching follow counts:', errorFollowerCount || errorFollowingCount);
46→    }
47→
48→    return {
49→        userData: [user],
50→        followerCount: followerCount || 0,
51→        followingCount: followingCount || 0
52→    };
53→}
54→
55→export const getUserDataService = async(userId) =>{
56→    if(!userId){
57→        throw {status: 400, message: 'userid is undefined'}
58→    }
59→    const userDataPromise = supabase
60→    .from('users')
61→    .select('*')
62→    .eq('id', userId)
63→
64→    const followerCountPromise = supabase
65→    .from('follows')
66→    .select('*', {count: 'exact', head: true})
67→    .eq('following_id', userId)
68→
69→    const followingCountPromise = supabase
70→    .from('follows')
71→    .select('*', {count: 'exact', head: true})
72→    .eq('follower_id', userId)
73→
74→    const [userDataResult, followerCountResult, followingCountResult] = await Promise.all([
75→        userDataPromise, followerCountPromise, followingCountPromise
76→    ])
77→
78→    const {data: userData, error: errorUserData} = userDataResult;
79→    const {count: followerCount, error: errorFollowerCount} = followerCountResult;
80→    const {count: followingCount, error: errorFollowingCount} = followingCountResult;
81→
82→    if(errorUserData || errorFollowerCount || errorFollowingCount){
83→        console.error('supabase error while fetching user data:', errorUserData || errorFollowerCount || errorFollowingCount)
84→        throw {status: 400, message: 'supabase error while fetching user data'}
85→    }
86→    const data = {userData: userData, followerCount: followerCount, followingCount: followingCount}
87→    return data;
88→}

