  1→import { useEffect, useState } from 'react';
  2→import { getBookmarks } from '../../../API/Api';
  3→import { useAuth } from '../../Context/useAuth';
  4→import './bookmarks.css';
  5→import { useInfiniteQuery, useQueryClient } from '@tanstack/react-query';
  6→import ParseContent from '../HomePage/postCards/parseData';
  7→import CalculateText from '../HomePage/postCards/calculateReadingTime';
  8→import { MoonLoader } from 'react-spinners';
  9→import { motion, AnimatePresence } from 'framer-motion';
 10→import { handleCLickContent, handleClickProfile } from '../../../helpers/handleClicks';
 11→import { useNavigate } from 'react-router-dom';
 12→import { useInView } from 'react-intersection-observer';
 13→import { useRef } from 'react';
 14→import VerifiedBadge from '../Badge/VerifiedBadge';
 15→import formatPostDate from '../../../helpers/formatDateString';
 16→import { handleImageFallback } from '../../utils/handleImageFallback';
 17→
 18→const Bookmarks = () =>{
 19→    const {user, session} = useAuth();
 20→    const userId = user?.userData?.[0].id
 21→    const navigate = useNavigate();
 22→
 23→    const {ref: inviewRef, inView} = useInView({
 24→        threshold: 0.2
 25→    });
 26→    const timeOutRef = useRef();
 27→    const scrollToTop = useRef();
 28→    const modalRef = useRef(null);
 29→
 30→    const [bookmarkIdSettings, setBookmarkIdSettings] = useState('');
 31→    const [showHeaders, setShowHeaders] = useState(true);
 32→
 33→    const handleclickUserProfile = handleClickProfile(navigate);
 34→
 35→    const handleClickBookmarkSettings = (e, journalId) => {
 36→        e.stopPropagation();
 37→        setBookmarkIdSettings(journalId === bookmarkIdSettings ? null : journalId)
 38→    }
 39→
 40→    const handleBackLocation = (e) =>{
 41→        e.stopPropagation();
 42→        window.history.back();
 43→    }
 44→
 45→    const handleClick = handleCLickContent(navigate);
 46→
 47→    const queryClient = useQueryClient();
 48→    const {data, isLoading, isFetchingNextPage, hasNextPage, fetchNextPage} = useInfiniteQuery({
 49→        queryKey: ['getBookmarks', userId],
 50→        queryFn: ({queryKey, pageParam = null}) => getBookmarks(pageParam, 5, queryKey[1], session?.access_token),
 51→        getNextPageParam: (lastPage) => {
 52→            if(lastPage?.hasMore){
 53→                const lastBookmark = lastPage.bookmarks[lastPage?.bookmarks?.length - 1];
 54→                return new Date(lastBookmark.created_at).toISOString();
 55→            } else {
 56→                return undefined;
 57→            }
 58→        },
 59→        enabled: !!userId,
 60→        refetchOnWindowFocus: false,
 61→        staleTime: 1000 * 60 * 5,
 62→    })
 63→
 64→    useEffect(() =>{
 65→        if(inView && hasNextPage && !isFetchingNextPage){
 66→            fetchNextPage();
 67→        }
 68→
 69→    }, [hasNextPage, fetchNextPage, isFetchingNextPage, inView])
 70→
 71→    useEffect(() =>{
 72→        const scroll = () =>{
 73→            setShowHeaders(false)
 74→            if(timeOutRef.current){
 75→                clearTimeout(timeOutRef.current)
 76→            }
 77→            timeOutRef.current = setTimeout(() =>{
 78→                setShowHeaders(true)
 79→            }, 500)
 80→        }
 81→
 82→        document.addEventListener('scroll', scroll, true)
 83→        return () =>{
 84→             if(timeOutRef.current){
 85→                clearTimeout(timeOutRef.current);
 86→            }
 87→            document.removeEventListener('scroll', scroll, true)
 88→        }
 89→    }, [])
 90→
 91→    useEffect(() =>{
 92→        // console.log(data)
 93→    }, [data])
 94→
 95→    useEffect(() => {
 96→        const handleClickOutside = (e) =>{
 97→            if(modalRef.current && !modalRef.current.contains(e.target)){
 98→                setBookmarkIdSettings(null)
 99→            }
100→        }
101→        window.addEventListener('click', handleClickOutside)
102→        return() => {
103→            window.removeEventListener('click', handleClickOutside)
104→        }
105→    }, [])
106→
107→    const journals = data?.pages?.flatMap((journal) => journal.bookmarks|| []);
108→    const totalBookmarks = data?.pages?.flatMap((journal) => journal.totalBookmarks)
109→
110→    useEffect(() => {
111→        if(!isLoading && scrollToTop.current){
112→            scrollToTop.current.scrollIntoView({behavior: 'smooth'});
113→        }
114→    }, [isLoading])
115→
116→    if(isLoading){
117→        return(
118→            <div className='bookmark-loading-container'>
119→                <MoonLoader loading={isLoading} color="var(--loader-color)" speedMultiplier={1} size={20}/>
120→            </div>
121→        )
122→    }
123→    if(journals?.length === 0){
124→        return(
125→            <div className='bookmark-parent-container'>
126→                <p>No bookmarks available</p>
127→            </div>
128→        )
129→    }
130→
131→
132→    return(
133→        <>
134→        <div ref={scrollToTop}/>
135→        <AnimatePresence>
136→        {showHeaders && (
137→            <motion.div
138→            className='bookmarks-header'
139→            initial={{opacity: 0}}
140→            animate={{opacity: 1, transition:{ type: 'spring', stiffness: 300, damping: 25, mass: 0.8}}}
141→            exit={{opacity:0, y: -20, transition:{duration: 0.2, ease: 'easeInOut'}}}
142→            >
143→                <div onClick={(e) => handleBackLocation(e)} className='back-button'>
144→                    <svg xmlns="http://www.w3.org/2000/svg" height="24px" viewBox="0 -960 960 960" width="24px" fill="currentColor"><path d="M360-240 120-480l240-240 56 56-144 144h568v80H272l144 144-56 56Z"/></svg>
145→                </div>
146→
147→                <p className='bookmarks-header-text'>Bookmarks <span className='bookmarks-header-count'>({totalBookmarks})</span></p>
148→            </motion.div>
149→        )}
150→        </AnimatePresence>
151→
152→        <div className='bookmark-parent-container'>
153→            {journals?.map((journal, index) => {
154→                const parsedContent = ParseContent(journal.journals.content);
155→                return(
156→                    <motion.div
157→                        className='bookmark-card'
158→                        key={journal.journals.id || index}
159→                    >
160→
161→                        {parsedContent.firstImage && (
162→                            <img
163→                                className="bookmark-card-image-banner"
164→                                src={parsedContent.firstImage.src}
165→                                alt={journal?.journals?.title ? `${journal.journals.title} cover image` : "Bookmarked post cover image"}
166→                                loading="lazy"
167→                                onError={handleImageFallback}
168→                                onClick={(e) => handleClick(
169→                                    e,
170→                                    journal.journals.content,
171→                                    parsedContent.wholeText,
172→                                    journal.journals.title,
173→                                    journal.journals.user_id,
174→                                    journal.journals.users.name,
175→                                    journal.journals.users.image_url,
176→                                    journal.journals.created_at,
