  <WelcomeFlow
    userName={user?.userData?.[0]?.name}
    userAvatar={user?.userData?.[0]?.image_url}
    onClose={() => setShowWelcomeFlow(false)}
    onAction={(action) => {
      setShowWelcomeFlow(false);
      if (action === 'write') handleOpenTextEditor();
