### OnboardingChecklist Component

```jsx
const CHECKLIST_ITEMS = [
  { key: 'profile', label: 'Complete your profile', icon: <UserIcon /> },
  { key: 'firstPost', label: 'Write your first post', icon: <PenIcon />, action: 'write' },
  { key: 'followWriter', label: 'Follow a writer', icon: <UsersIcon />, action: 'explore' },
  { key: 'exploreTrending', label: 'Explore trending posts', icon: <CompassIcon />, action: 'explore' },
  { key: 'saveBookmark', label: 'Save a bookmark', icon: <BookmarkIcon />, action: 'bookmark' },
];

const OnboardingChecklist = ({ onOpenEditor, onNavigate }) => {
  const { checklist, checklistDismissed, dismissChecklist, isAllChecklistComplete } = useOnboarding();
  const [isCollapsed, setIsCollapsed] = useState(false);

  if (checklistDismissed || isAllChecklistComplete()) return null;

  const completedCount = Object.values(checklist).filter(Boolean).length;
  const total = CHECKLIST_ITEMS.length;
  const progressPct = (completedCount / total) * 100;

  return (
    <motion.div
      className="onboarding-checklist"
      initial={{ opacity: 0, y: 20 }}
      animate={{ opacity: 1, y: 0, transition: { type: 'spring', stiffness: 350, damping: 28, delay: 1 } }}
    >
      <div className="checklist-header">
        <div className="checklist-header-left">
          <h4 className="checklist-title onboarding-ui-text">Getting started</h4>
          <span className="checklist-progress-label">{completedCount}/{total}</span>
        </div>
        <div className="checklist-header-actions">
          <button className="checklist-collapse-btn" onClick={() => setIsCollapsed(!isCollapsed)}>
            {/* chevron SVG */}
          </button>
          <button className="checklist-dismiss-btn" onClick={dismissChecklist}>
            {/* X SVG */}
          </button>
        </div>
      </div>

      {/* Progress bar */}
      <div className="checklist-progress-bar">
        <motion.div
          className="checklist-progress-fill"
          animate={{ width: `${progressPct}%` }}
          transition={{ type: 'spring', stiffness: 200, damping: 20 }}
        />
      </div>

      <AnimatePresence>
      {!isCollapsed && (
        <motion.div
          className="checklist-items"
          initial={{ height: 0, opacity: 0 }}
          animate={{ height: 'auto', opacity: 1 }}
          exit={{ height: 0, opacity: 0 }}
          transition={{ duration: 0.25, ease: 'easeInOut' }}
        >
          {CHECKLIST_ITEMS.map((item) => (
            <ChecklistItem
              key={item.key}
              completed={checklist[item.key]}
              label={item.label}
              icon={item.icon}
              onAction={() => {
                if (item.action === 'write') onOpenEditor();
                if (item.action === 'explore') onNavigate('/home/explore');
                if (item.action === 'bookmark') onNavigate('/home/bookmark');
              }}
            />
          ))}
        </motion.div>
      )}
      </AnimatePresence>
    </motion.div>
  );
};
```

