### SpotlightTip Component

This component uses a `ref` callback to measure the target element's position and renders a floating card adjacent to it. It does NOT use a blocking overlay -- instead it uses a subtle highlight ring around the target element via `box-shadow` with an animated gold glow.

```jsx
const SpotlightTip = ({ tipId, targetRef, title, body, position = 'bottom', onDismiss }) => {
  const { isTipSeen, markTipSeen, isTipsGlobalOff } = useOnboarding();
  const [coords, setCoords] = useState(null);

  useEffect(() => {
    if (!targetRef?.current) return;
    const rect = targetRef.current.getBoundingClientRect();
    setCoords(calculatePosition(rect, position));
  }, [targetRef, position]);

  if (isTipsGlobalOff || isTipSeen(tipId) || !coords) return null;

  const handleDismiss = () => {
    markTipSeen(tipId);
    onDismiss?.();
  };

  return (
    <AnimatePresence>
      <motion.div
        className="spotlight-tip"
        style={{ top: coords.top, left: coords.left }}
        initial={{ opacity: 0, y: 8, scale: 0.95 }}
        animate={{ opacity: 1, y: 0, scale: 1, transition: { type: 'spring', stiffness: 400, damping: 25 } }}
        exit={{ opacity: 0, y: 4, scale: 0.97, transition: { duration: 0.15 } }}
      >
        <div className="spotlight-tip-arrow" data-position={position} />
        <div className="spotlight-tip-content">
          <h4 className="spotlight-tip-title onboarding-ui-text">{title}</h4>
          <p className="spotlight-tip-body onboarding-body-text">{body}</p>
        </div>
        <button className="spotlight-tip-dismiss" onClick={handleDismiss}>Got it</button>
      </motion.div>
    </AnimatePresence>
  );
};
```

