### SpotlightManager

Placed inside `Home.jsx` (or its child routes), this component checks the current route and renders `SpotlightTip` components for relevant tips after a 2-second delay (so the user has time to orient before tips appear).

```jsx
const SpotlightManager = ({ writeButtonRef, exploreRef, storiesRef, universeRef }) => {
  const { isTipsGlobalOff, isTipSeen } = useOnboarding();
  const location = useLocation();
  const [ready, setReady] = useState(false);

  useEffect(() => {
    const timer = setTimeout(() => setReady(true), 2000);
    return () => clearTimeout(timer);
  }, []);

  if (!ready || isTipsGlobalOff) return null;

  // Only show tips relevant to the current page
  // Show at most 1 tip at a time -- pick the first unseen one
  const tipsForPage = Object.values(TIP_DEFINITIONS)
    .filter(tip => location.pathname.startsWith(tip.page))
    .filter(tip => !isTipSeen(tip.id));

  if (tipsForPage.length === 0) return null;

  const activeTip = tipsForPage[0]; // show only one at a time
  // Map tip IDs to refs...

  return <SpotlightTip tipId={activeTip.id} targetRef={refMap[activeTip.id]} ... />;
};
```

